    11→
    12→export async function execute(ctx: AdapterExecutionContext): Promise<AdapterExecutionResult> {
    13→  const { runId, agent, config, onLog, onMeta } = ctx;
    14→  const command = asString(config.command, "");
    15→  if (!command) throw new Error("Process adapter missing command");
    16→
    17→  const args = asStringArray(config.args);
    18→  const cwd = asString(config.cwd, process.cwd());
    19→  const envConfig = parseObject(config.env);
    20→  const env: Record<string, string> = { ...buildPaperclipEnv(agent) };
    21→  for (const [k, v] of Object.entries(envConfig)) {
    22→    if (typeof v === "string") env[k] = v;
    23→  }
    24→
    25→  const timeoutSec = asNumber(config.timeoutSec, 0);
    26→  const graceSec = asNumber(config.graceSec, 15);
    27→
    28→  if (onMeta) {
    29→    await onMeta({
    30→      adapterType: "process",
    31→      command,
    32→      cwd,
    33→      commandArgs: args,
    34→      env: redactEnvForLogs(env),
    35→    });
    36→  }
    37→
    38→  const proc = await runChildProcess(runId, command, args, {
    39→    cwd,
    40→    env,
    41→    timeoutSec,
    42→    graceSec,
    43→    onLog,
    44→  });
    45→
    46→  if (proc.timedOut) {
    47→    return {
    48→      exitCode: proc.exitCode,
    49→      signal: proc.signal,
    50→      timedOut: true,
    51→      errorMessage: `Timed out after ${timeoutSec}s`,
    52→    };
    53→  }
    54→
    55→  if ((proc.exitCode ?? 0) !== 0) {
    56→    return {
    57→      exitCode: proc.exitCode,
    58→      signal: proc.signal,
    59→      timedOut: false,
    60→      errorMessage: `Process exited with code ${proc.exitCode ?? -1}`,
    61→      resultJson: {
    62→        stdout: proc.stdout,
    63→        stderr: proc.stderr,
    64→      },
    65→    };
    66→  }
    67→
    68→  return {
    69→    exitCode: proc.exitCode,
    70→    signal: proc.signal,
    71→    timedOut: false,
    72→    resultJson: {
    73→      stdout: proc.stdout,
    74→      stderr: proc.stderr,
    75→    },
