    16→
    17→function isSafeIdentifier(value: string): boolean {
    18→  return /^[A-Za-z_][A-Za-z0-9_]*$/.test(value);
    19→}
    20→
    21→function quoteIdentifier(value: string): string {
    22→  if (!isSafeIdentifier(value)) throw new Error(`Unsafe SQL identifier: ${value}`);
    23→  return `"${value.replaceAll("\"", "\"\"")}"`;
    24→}
    25→
    26→function quoteLiteral(value: string): string {
    27→  return `'${value.replaceAll("'", "''")}'`;
