    53→async function listMigrationFiles(): Promise<string[]> {
    54→  const entries = await readdir(MIGRATIONS_FOLDER, { withFileTypes: true });
    55→  return entries
    56→    .filter((entry) => entry.isFile() && entry.name.endsWith(".sql"))
    57→    .map((entry) => entry.name)
    58→    .sort((a, b) => a.localeCompare(b));
    59→}
    60→
    61→type MigrationJournalFile = {
    62→  entries?: Array<{ idx?: number; tag?: string; when?: number }>;
    63→};
    64→
    65→type JournalMigrationEntry = {
    66→  fileName: string;
    67→  folderMillis: number;
    68→  order: number;
    69→};
    70→
    71→async function listJournalMigrationEntries(): Promise<JournalMigrationEntry[]> {
    72→  try {
    73→    const raw = await readFile(MIGRATIONS_JOURNAL_JSON, "utf8");
    74→    const parsed = JSON.parse(raw) as MigrationJournalFile;
    75→    if (!Array.isArray(parsed.entries)) return [];
    76→    return parsed.entries
    77→      .map((entry, entryIndex) => {
    78→        if (typeof entry?.tag !== "string") return null;
    79→        if (typeof entry?.when !== "number" || !Number.isFinite(entry.when)) return null;
    80→        const order = Number.isInteger(entry.idx) ? Number(entry.idx) : entryIndex;
    81→        return { fileName: `${entry.tag}.sql`, folderMillis: entry.when, order };
    82→      })
    83→      .filter((entry): entry is JournalMigrationEntry => entry !== null);
    84→  } catch {
    85→    return [];
    86→  }
    87→}
    88→
    89→async function listJournalMigrationFiles(): Promise<string[]> {
    90→  const entries = await listJournalMigrationEntries();
