    97→
    98→async function orderMigrationsByJournal(migrationFiles: string[]): Promise<string[]> {
    99→  const journalEntries = await listJournalMigrationEntries();
   100→  const orderByFileName = new Map(journalEntries.map((entry) => [entry.fileName, entry.order]));
   101→  return [...migrationFiles].sort((left, right) => {
   102→    const leftOrder = orderByFileName.get(left);
   103→    const rightOrder = orderByFileName.get(right);
   104→    if (leftOrder === undefined && rightOrder === undefined) return left.localeCompare(right);
   105→    if (leftOrder === undefined) return 1;
   106→    if (rightOrder === undefined) return -1;
   107→    if (leftOrder === rightOrder) return left.localeCompare(right);
   108→    return leftOrder - rightOrder;
   109→  });
   110→}
