   112→type SqlExecutor = Pick<ReturnType<typeof postgres>, "unsafe">;
   113→
   114→async function runInTransaction(sql: SqlExecutor, action: () => Promise<void>): Promise<void> {
   115→  await sql.unsafe("BEGIN");
   116→  try {
   117→    await action();
   118→    await sql.unsafe("COMMIT");
   119→  } catch (error) {
   120→    try {
   121→      await sql.unsafe("ROLLBACK");
   122→    } catch {
   123→      // Ignore rollback failures and surface the original error.
   124→    }
   125→    throw error;
   126→  }
   127→}
