   129→async function latestMigrationCreatedAt(
   130→  sql: SqlExecutor,
   131→  qualifiedTable: string,
   132→): Promise<number | null> {
   133→  const rows = await sql.unsafe<{ created_at: string | number | null }[]>(
   134→    `SELECT created_at FROM ${qualifiedTable} ORDER BY created_at DESC NULLS LAST LIMIT 1`,
   135→  );
   136→  const value = Number(rows[0]?.created_at ?? Number.NaN);
   137→  return Number.isFinite(value) ? value : null;
   138→}
   139→
   140→function normalizeFolderMillis(value: number | null | undefined): number {
   141→  if (typeof value === "number" && Number.isFinite(value) && value >= 0) {
   142→    return Math.trunc(value);
   143→  }
   144→  return Date.now();
   145→}
