   147→async function ensureMigrationJournalTable(
   148→  sql: ReturnType<typeof postgres>,
   149→): Promise<{ migrationTableSchema: string; columnNames: Set<string> }> {
   150→  let migrationTableSchema = await discoverMigrationTableSchema(sql);
   151→  if (!migrationTableSchema) {
   152→    const drizzleSchema = quoteIdentifier("drizzle");
   153→    const migrationTable = quoteIdentifier(DRIZZLE_MIGRATIONS_TABLE);
   154→    await sql.unsafe(`CREATE SCHEMA IF NOT EXISTS ${drizzleSchema}`);
   155→    await sql.unsafe(
   156→      `CREATE TABLE IF NOT EXISTS ${drizzleSchema}.${migrationTable} (id SERIAL PRIMARY KEY, hash text NOT NULL, created_at bigint)`,
   157→    );
   158→    migrationTableSchema = (await discoverMigrationTableSchema(sql)) ?? "drizzle";
   159→  }
   160→
   161→  const columnNames = await getMigrationTableColumnNames(sql, migrationTableSchema);
   162→  return { migrationTableSchema, columnNames };
   163→}
   164→
   165→async function migrationHistoryEntryExists(
   166→  sql: SqlExecutor,
   167→  qualifiedTable: string,
   168→  columnNames: Set<string>,
   169→  migrationFile: string,
   170→  hash: string,
   171→): Promise<boolean> {
   172→  const predicates: string[] = [];
   173→  if (columnNames.has("hash")) predicates.push(`hash = ${quoteLiteral(hash)}`);
   174→  if (columnNames.has("name")) predicates.push(`name = ${quoteLiteral(migrationFile)}`);
   175→  if (predicates.length === 0) return false;
   176→
   177→  const rows = await sql.unsafe<{ one: number }[]>(
   178→    `SELECT 1 AS one FROM ${qualifiedTable} WHERE ${predicates.join(" OR ")} LIMIT 1`,
   179→  );
   180→  return rows.length > 0;
   181→}
   182→
   183→async function recordMigrationHistoryEntry(
   184→  sql: SqlExecutor,
   185→  qualifiedTable: string,
   186→  columnNames: Set<string>,
   187→  migrationFile: string,
   188→  hash: string,
   189→  folderMillis: number,
   190→): Promise<void> {
   191→  const insertColumns: string[] = [];
   192→  const insertValues: string[] = [];
   193→
   194→  if (columnNames.has("hash")) {
   195→    insertColumns.push(quoteIdentifier("hash"));
   196→    insertValues.push(quoteLiteral(hash));
   197→  }
   198→  if (columnNames.has("name")) {
   199→    insertColumns.push(quoteIdentifier("name"));
   200→    insertValues.push(quoteLiteral(migrationFile));
   201→  }
   202→  if (columnNames.has("created_at")) {
   203→    const latestCreatedAt = await latestMigrationCreatedAt(sql, qualifiedTable);
   204→    const createdAt = latestCreatedAt === null
   205→      ? normalizeFolderMillis(folderMillis)
   206→      : Math.max(latestCreatedAt + 1, normalizeFolderMillis(folderMillis));
   207→    insertColumns.push(quoteIdentifier("created_at"));
   208→    insertValues.push(quoteLiteral(String(createdAt)));
   209→  }
   210→
   211→  if (insertColumns.length === 0) return;
   212→
   213→  await sql.unsafe(
   214→    `INSERT INTO ${qualifiedTable} (${insertColumns.join(", ")}) VALUES (${insertValues.join(", ")})`,
   215→  );
   216→}
   217→
   218→async function applyPendingMigrationsManually(
   219→  url: string,
   220→  pendingMigrations: string[],
   221→): Promise<void> {
   222→  if (pendingMigrations.length === 0) return;
   223→
   224→  const orderedPendingMigrations = await orderMigrationsByJournal(pendingMigrations);
   225→  const journalEntries = await listJournalMigrationEntries();
   226→  const folderMillisByFileName = new Map(
   227→    journalEntries.map((entry) => [entry.fileName, normalizeFolderMillis(entry.folderMillis)]),
   228→  );
   229→
   230→  const sql = createUtilitySql(url);
   231→  try {
   232→    const { migrationTableSchema, columnNames } = await ensureMigrationJournalTable(sql);
   233→    const qualifiedTable = `${quoteIdentifier(migrationTableSchema)}.${quoteIdentifier(DRIZZLE_MIGRATIONS_TABLE)}`;
   234→
   235→    for (const migrationFile of orderedPendingMigrations) {
   236→      const migrationContent = await readMigrationFileContent(migrationFile);
   237→      const hash = createHash("sha256").update(migrationContent).digest("hex");
   238→      const existingEntry = await migrationHistoryEntryExists(
   239→        sql,
   240→        qualifiedTable,
   241→        columnNames,
   242→        migrationFile,
   243→        hash,
   244→      );
   245→      if (existingEntry) continue;
   246→
   247→      await runInTransaction(sql, async () => {
   248→        for (const statement of splitMigrationStatements(migrationContent)) {
   249→          await sql.unsafe(statement);
   250→        }
   251→
   252→        await recordMigrationHistoryEntry(
   253→          sql,
   254→          qualifiedTable,
   255→          columnNames,
   256→          migrationFile,
   257→          hash,
   258→          folderMillisByFileName.get(migrationFile) ?? Date.now(),
   259→        );
   260→      });
   261→    }
   262→  } finally {
   263→    await sql.end();
   264→  }
   265→}
