   267→async function mapHashesToMigrationFiles(migrationFiles: string[]): Promise<Map<string, string>> {
   268→  const mapped = new Map<string, string>();
   269→
   270→  await Promise.all(
   271→    migrationFiles.map(async (migrationFile) => {
