   296→async function tableExists(
   297→  sql: ReturnType<typeof postgres>,
   298→  tableName: string,
   299→): Promise<boolean> {
   300→  const rows = await sql<{ exists: boolean }[]>`
   301→    SELECT EXISTS (
   302→      SELECT 1
   303→      FROM information_schema.tables
   304→      WHERE table_schema = 'public'
   305→        AND table_name = ${tableName}
