   311→async function columnExists(
   312→  sql: ReturnType<typeof postgres>,
   313→  tableName: string,
   314→  columnName: string,
   315→): Promise<boolean> {
   316→  const rows = await sql<{ exists: boolean }[]>`
   317→    SELECT EXISTS (
   318→      SELECT 1
   319→      FROM information_schema.columns
   320→      WHERE table_schema = 'public'
   321→        AND table_name = ${tableName}
   322→        AND column_name = ${columnName}
