   328→async function indexExists(
   329→  sql: ReturnType<typeof postgres>,
   330→  indexName: string,
   331→): Promise<boolean> {
   332→  const rows = await sql<{ exists: boolean }[]>`
   333→    SELECT EXISTS (
   334→      SELECT 1
   335→      FROM pg_class c
   336→      JOIN pg_namespace n ON n.oid = c.relnamespace
