   360→
   361→async function migrationStatementAlreadyApplied(
   362→  sql: ReturnType<typeof postgres>,
   363→  statement: string,
   364→): Promise<boolean> {
   365→  const normalized = statement.replace(/\s+/g, " ").trim();
   366→
   367→  const createTableMatch = normalized.match(/^CREATE TABLE(?: IF NOT EXISTS)? "([^"]+)"/i);
   368→  if (createTableMatch) {
   369→    return tableExists(sql, createTableMatch[1]);
   370→  }
   371→
   372→  const addColumnMatch = normalized.match(
   373→    /^ALTER TABLE "([^"]+)" ADD COLUMN(?: IF NOT EXISTS)? "([^"]+)"/i,
   374→  );
   375→  if (addColumnMatch) {
   376→    return columnExists(sql, addColumnMatch[1], addColumnMatch[2]);
   377→  }
   378→
   379→  const createIndexMatch = normalized.match(/^CREATE (?:UNIQUE )?INDEX(?: IF NOT EXISTS)? "([^"]+)"/i);
   380→  if (createIndexMatch) {
   381→    return indexExists(sql, createIndexMatch[1]);
   382→  }
   383→
   384→  const addConstraintMatch = normalized.match(/^ALTER TABLE "([^"]+)" ADD CONSTRAINT "([^"]+)"/i);
   385→  if (addConstraintMatch) {
   386→    return constraintExists(sql, addConstraintMatch[2]);
   387→  }
   388→
   389→  // If we cannot reason about a statement safely, require manual migration.
   390→  return false;
   391→}
