   393→async function migrationContentAlreadyApplied(
   394→  sql: ReturnType<typeof postgres>,
   395→  migrationContent: string,
   396→): Promise<boolean> {
   397→  const statements = splitMigrationStatements(migrationContent);
   398→  if (statements.length === 0) return false;
   399→
   400→  for (const statement of statements) {
   401→    const applied = await migrationStatementAlreadyApplied(sql, statement);
   402→    if (!applied) return false;
   403→  }
   404→
   405→  return true;
   406→}
