   408→async function loadAppliedMigrations(
   409→  sql: ReturnType<typeof postgres>,
   410→  migrationTableSchema: string,
   411→  availableMigrations: string[],
   412→): Promise<string[]> {
   413→  const quotedSchema = quoteIdentifier(migrationTableSchema);
   414→  const qualifiedTable = `${quotedSchema}.${quoteIdentifier(DRIZZLE_MIGRATIONS_TABLE)}`;
   415→  const columnNames = await getMigrationTableColumnNames(sql, migrationTableSchema);
   416→
   417→  if (columnNames.has("name")) {
   418→    const rows = await sql.unsafe<{ name: string }[]>(`SELECT name FROM ${qualifiedTable} ORDER BY id`);
   419→    return rows.map((row) => row.name).filter((name): name is string => Boolean(name));
   420→  }
   421→
   422→  if (columnNames.has("hash")) {
   423→    const rows = await sql.unsafe<{ hash: string }[]>(`SELECT hash FROM ${qualifiedTable} ORDER BY id`);
   424→    const hashesToMigrationFiles = await mapHashesToMigrationFiles(availableMigrations);
   425→    const appliedFromHashes = rows
   426→      .map((row) => hashesToMigrationFiles.get(row.hash))
   427→      .filter((name): name is string => Boolean(name));
   428→
   429→    if (appliedFromHashes.length > 0) {
   430→      // Best-effort: when all hashes resolve, this is authoritative.
   431→      if (appliedFromHashes.length === rows.length) return appliedFromHashes;
   432→
   433→      // Partial hash resolution can happen when files have changed; return what we can trust.
   434→      return appliedFromHashes;
   435→    }
   436→
   437→    // Fallback only when hashes are unavailable/unresolved.
   438→    if (columnNames.has("created_at")) {
   439→      const journalEntries = await listJournalMigrationEntries();
   440→      if (journalEntries.length > 0) {
   441→        const lastDbRows = await sql.unsafe<{ created_at: string | number | null }[]>(
   442→          `SELECT created_at FROM ${qualifiedTable} ORDER BY created_at DESC LIMIT 1`,
   443→        );
   444→        const lastCreatedAt = Number(lastDbRows[0]?.created_at ?? -1);
   445→        if (Number.isFinite(lastCreatedAt) && lastCreatedAt >= 0) {
   446→          return journalEntries
   447→            .filter((entry) => availableMigrations.includes(entry.fileName))
   448→            .filter((entry) => entry.folderMillis <= lastCreatedAt)
   449→            .map((entry) => entry.fileName)
   450→            .slice(0, rows.length);
   451→        }
   452→      }
   453→    }
   454→  }
   455→
   456→  const rows = await sql.unsafe<{ id: number }[]>(`SELECT id FROM ${qualifiedTable} ORDER BY id`);
   457→  const journalMigrationFiles = await listJournalMigrationFiles();
   458→  const appliedFromIds = rows
   459→    .map((row) => journalMigrationFiles[row.id - 1])
   460→    .filter((name): name is string => Boolean(name));
   461→  if (appliedFromIds.length > 0) return appliedFromIds;
   462→
   463→  return availableMigrations.slice(0, Math.max(0, rows.length));
   464→}
