   471→export async function reconcilePendingMigrationHistory(
   472→  url: string,
   473→): Promise<MigrationHistoryReconcileResult> {
   474→  const state = await inspectMigrations(url);
   475→  if (state.status !== "needsMigrations" || state.reason !== "pending-migrations") {
   476→    return { repairedMigrations: [], remainingMigrations: [] };
   477→  }
   478→
   479→  const sql = createUtilitySql(url);
   480→  const repairedMigrations: string[] = [];
   481→
   482→  try {
   483→    const journalEntries = await listJournalMigrationEntries();
   484→    const folderMillisByFile = new Map(journalEntries.map((entry) => [entry.fileName, entry.folderMillis]));
   485→    const migrationTableSchema = await discoverMigrationTableSchema(sql);
   486→    if (!migrationTableSchema) {
   487→      return { repairedMigrations, remainingMigrations: state.pendingMigrations };
   488→    }
   489→
   490→    const columnNames = await getMigrationTableColumnNames(sql, migrationTableSchema);
   491→    const qualifiedTable = `${quoteIdentifier(migrationTableSchema)}.${quoteIdentifier(DRIZZLE_MIGRATIONS_TABLE)}`;
   492→
   493→    for (const migrationFile of state.pendingMigrations) {
   494→      const migrationContent = await readMigrationFileContent(migrationFile);
   495→      const alreadyApplied = await migrationContentAlreadyApplied(sql, migrationContent);
   496→      if (!alreadyApplied) break;
   497→
   498→      const hash = createHash("sha256").update(migrationContent).digest("hex");
   499→      const folderMillis = folderMillisByFile.get(migrationFile) ?? Date.now();
   500→      const existingByHash = columnNames.has("hash")
   501→        ? await sql.unsafe<{ created_at: string | number | null }[]>(
   502→            `SELECT created_at FROM ${qualifiedTable} WHERE hash = ${quoteLiteral(hash)} ORDER BY created_at DESC LIMIT 1`,
   503→          )
   504→        : [];
   505→      const existingByName = columnNames.has("name")
   506→        ? await sql.unsafe<{ created_at: string | number | null }[]>(
   507→            `SELECT created_at FROM ${qualifiedTable} WHERE name = ${quoteLiteral(migrationFile)} ORDER BY created_at DESC LIMIT 1`,
   508→          )
   509→        : [];
   510→      if (existingByHash.length > 0 || existingByName.length > 0) {
   511→        if (columnNames.has("created_at")) {
   512→          const existingHashCreatedAt = Number(existingByHash[0]?.created_at ?? -1);
   513→          if (existingByHash.length > 0 && Number.isFinite(existingHashCreatedAt) && existingHashCreatedAt < folderMillis) {
   514→            await sql.unsafe(
   515→              `UPDATE ${qualifiedTable} SET created_at = ${quoteLiteral(String(folderMillis))} WHERE hash = ${quoteLiteral(hash)} AND created_at < ${quoteLiteral(String(folderMillis))}`,
   516→            );
   517→          }
   518→
   519→          const existingNameCreatedAt = Number(existingByName[0]?.created_at ?? -1);
   520→          if (existingByName.length > 0 && Number.isFinite(existingNameCreatedAt) && existingNameCreatedAt < folderMillis) {
   521→            await sql.unsafe(
   522→              `UPDATE ${qualifiedTable} SET created_at = ${quoteLiteral(String(folderMillis))} WHERE name = ${quoteLiteral(migrationFile)} AND created_at < ${quoteLiteral(String(folderMillis))}`,
   523→            );
   524→          }
   525→        }
   526→
   527→        repairedMigrations.push(migrationFile);
   528→        continue;
   529→      }
   530→
   531→      const insertColumns: string[] = [];
   532→      const insertValues: string[] = [];
   533→
   534→      if (columnNames.has("hash")) {
   535→        insertColumns.push(quoteIdentifier("hash"));
   536→        insertValues.push(quoteLiteral(hash));
   537→      }
   538→      if (columnNames.has("name")) {
   539→        insertColumns.push(quoteIdentifier("name"));
   540→        insertValues.push(quoteLiteral(migrationFile));
   541→      }
   542→      if (columnNames.has("created_at")) {
   543→        insertColumns.push(quoteIdentifier("created_at"));
   544→        insertValues.push(quoteLiteral(String(folderMillis)));
   545→      }
   546→
   547→      if (insertColumns.length === 0) break;
   548→
   549→      await sql.unsafe(
   550→        `INSERT INTO ${qualifiedTable} (${insertColumns.join(", ")}) VALUES (${insertValues.join(", ")})`,
   551→      );
   552→      repairedMigrations.push(migrationFile);
   553→    }
   554→  } finally {
   555→    await sql.end();
   556→  }
   557→
   558→  const refreshed = await inspectMigrations(url);
   559→  return {
   560→    repairedMigrations,
   561→    remainingMigrations:
   562→      refreshed.status === "needsMigrations" ? refreshed.pendingMigrations : [],
   563→  };
   564→}
