   566→async function discoverMigrationTableSchema(sql: ReturnType<typeof postgres>): Promise<string | null> {
   567→  const rows = await sql<{ schemaName: string }[]>`
   568→    SELECT n.nspname AS "schemaName"
   569→    FROM pg_class c
   570→    JOIN pg_namespace n ON n.oid = c.relnamespace
   571→    WHERE c.relname = ${DRIZZLE_MIGRATIONS_TABLE} AND c.relkind = 'r'
   572→  `;
   573→
   574→  if (rows.length === 0) return null;
   575→
   576→  const drizzleSchema = rows.find(({ schemaName }) => schemaName === "drizzle");
   577→  if (drizzleSchema) return drizzleSchema.schemaName;
   578→
   579→  const publicSchema = rows.find(({ schemaName }) => schemaName === "public");
   580→  if (publicSchema) return publicSchema.schemaName;
   581→
   582→  return rows[0]?.schemaName ?? null;
   583→}
