   585→export async function inspectMigrations(url: string): Promise<MigrationState> {
   586→  const sql = createUtilitySql(url);
   587→
   588→  try {
   589→    const availableMigrations = await listMigrationFiles();
   590→    const tableCountResult = await sql<{ count: number }[]>`
   591→      select count(*)::int as count
   592→      from information_schema.tables
   593→      where table_schema = 'public'
   594→        and table_type = 'BASE TABLE'
   595→    `;
   596→    const tableCount = tableCountResult[0]?.count ?? 0;
   597→
   598→    const migrationTableSchema = await discoverMigrationTableSchema(sql);
   599→    if (!migrationTableSchema) {
   600→      if (tableCount > 0) {
   601→        return {
   602→          status: "needsMigrations",
   603→          tableCount,
   604→          availableMigrations,
   605→          appliedMigrations: [],
   606→          pendingMigrations: availableMigrations,
   607→          reason: "no-migration-journal-non-empty-db",
   608→        };
   609→      }
   610→
   611→      return {
   612→        status: "needsMigrations",
   613→        tableCount,
   614→        availableMigrations,
   615→        appliedMigrations: [],
   616→        pendingMigrations: availableMigrations,
   617→        reason: "no-migration-journal-empty-db",
   618→      };
   619→    }
   620→
   621→    const appliedMigrations = await loadAppliedMigrations(sql, migrationTableSchema, availableMigrations);
   622→    const pendingMigrations = availableMigrations.filter((name) => !appliedMigrations.includes(name));
   623→    if (pendingMigrations.length === 0) {
   624→      return {
   625→        status: "upToDate",
   626→        tableCount,
   627→        availableMigrations,
   628→        appliedMigrations,
   629→      };
   630→    }
   631→
   632→    return {
   633→      status: "needsMigrations",
   634→      tableCount,
   635→      availableMigrations,
   636→      appliedMigrations,
   637→      pendingMigrations,
   638→      reason: "pending-migrations",
   639→    };
   640→  } finally {
   641→    await sql.end();
   642→  }
   643→}
