   645→export async function applyPendingMigrations(url: string): Promise<void> {
   646→  const initialState = await inspectMigrations(url);
   647→  if (initialState.status === "upToDate") return;
   648→
   649→  const sql = createUtilitySql(url);
   650→
   651→  try {
   652→    const db = drizzlePg(sql);
   653→    await migratePg(db, { migrationsFolder: MIGRATIONS_FOLDER });
   654→  } finally {
   655→    await sql.end();
   656→  }
   657→
   658→  let state = await inspectMigrations(url);
   659→  if (state.status === "upToDate") return;
   660→
   661→  const repair = await reconcilePendingMigrationHistory(url);
   662→  if (repair.repairedMigrations.length > 0) {
   663→    state = await inspectMigrations(url);
   664→    if (state.status === "upToDate") return;
   665→  }
   666→
   667→  if (state.status !== "needsMigrations" || state.reason !== "pending-migrations") {
   668→    throw new Error("Migrations are still pending after attempted apply; run inspectMigrations for details.");
   669→  }
   670→
   671→  await applyPendingMigrationsManually(url, state.pendingMigrations);
   672→
   673→  const finalState = await inspectMigrations(url);
   674→  if (finalState.status !== "upToDate") {
   675→    throw new Error(
   676→      `Failed to apply pending migrations: ${finalState.pendingMigrations.join(", ")}`,
   677→    );
   678→  }
   679→}
