    74→function parseBearerToken(rawAuth: string | string[] | undefined) {
    75→  const auth = Array.isArray(rawAuth) ? rawAuth[0] : rawAuth;
    76→  if (!auth) return null;
    77→  if (!auth.toLowerCase().startsWith("bearer ")) return null;
    78→  const token = auth.slice("bearer ".length).trim();
    79→  return token.length > 0 ? token : null;
