   132→}
   133→
   134→function isLoopbackHost(hostname: string): boolean {
   135→  const value = hostname.trim().toLowerCase();
   136→  return value === "localhost" || value === "127.0.0.1" || value === "::1";
   137→}
   138→
   139→function normalizeHostname(value: string | null | undefined): string | null {
   140→  if (!value) return null;
   141→  const trimmed = value.trim();
   142→  if (!trimmed) return null;
   143→  if (trimmed.startsWith("[")) {
   144→    const end = trimmed.indexOf("]");
   145→    return end > 1
   146→      ? trimmed.slice(1, end).toLowerCase()
   147→      : trimmed.toLowerCase();
   148→  }
   149→  const firstColon = trimmed.indexOf(":");
   150→  if (firstColon > -1) return trimmed.slice(0, firstColon).toLowerCase();
   151→  return trimmed.toLowerCase();
   152→}
   153→
   154→function normalizeHeaderValue(
   155→  value: unknown,
   156→  depth: number = 0
   157→): string | null {
   158→  const direct = nonEmptyTrimmedString(value);
   159→  if (direct) return direct;
   160→  if (!isPlainObject(value) || depth >= 3) return null;
   161→
   162→  const candidateKeys = [
   163→    "value",
   164→    "token",
   165→    "secret",
   166→    "apiKey",
   167→    "api_key",
   168→    "auth",
   169→    "authToken",
   170→    "auth_token",
   171→    "accessToken",
   172→    "access_token",
   173→    "authorization",
   174→    "bearer",
   175→    "header",
   176→    "raw",
   177→    "text",
   178→    "string"
   179→  ];
   180→  for (const key of candidateKeys) {
   181→    if (!Object.prototype.hasOwnProperty.call(value, key)) continue;
   182→    const normalized = normalizeHeaderValue(
   183→      (value as Record<string, unknown>)[key],
   184→      depth + 1
   185→    );
   186→    if (normalized) return normalized;
   187→  }
   188→
   189→  const entries = Object.entries(value as Record<string, unknown>);
   190→  if (entries.length === 1) {
   191→    const [singleKey, singleValue] = entries[0];
   192→    const normalizedKey = singleKey.trim().toLowerCase();
   193→    if (
   194→      normalizedKey !== "type" &&
   195→      normalizedKey !== "version" &&
   196→      normalizedKey !== "secretid" &&
   197→      normalizedKey !== "secret_id"
   198→    ) {
   199→      const normalized = normalizeHeaderValue(singleValue, depth + 1);
   200→      if (normalized) return normalized;
   201→    }
   202→  }
   203→
   204→  return null;
   205→}
   206→
   207→function extractHeaderEntries(input: unknown): Array<[string, unknown]> {
   208→  if (isPlainObject(input)) {
   209→    return Object.entries(input);
   210→  }
   211→  if (!Array.isArray(input)) {
   212→    return [];
   213→  }
   214→
   215→  const entries: Array<[string, unknown]> = [];
   216→  for (const item of input) {
   217→    if (Array.isArray(item)) {
   218→      const key = nonEmptyTrimmedString(item[0]);
   219→      if (!key) continue;
   220→      entries.push([key, item[1]]);
   221→      continue;
   222→    }
   223→    if (!isPlainObject(item)) continue;
   224→
   225→    const mapped = item as Record<string, unknown>;
   226→    const explicitKey =
   227→      nonEmptyTrimmedString(mapped.key) ??
   228→      nonEmptyTrimmedString(mapped.name) ??
   229→      nonEmptyTrimmedString(mapped.header);
   230→    if (explicitKey) {
   231→      const explicitValue = Object.prototype.hasOwnProperty.call(
   232→        mapped,
   233→        "value"
   234→      )
   235→        ? mapped.value
   236→        : Object.prototype.hasOwnProperty.call(mapped, "token")
   237→        ? mapped.token
   238→        : Object.prototype.hasOwnProperty.call(mapped, "secret")
   239→        ? mapped.secret
   240→        : mapped;
   241→      entries.push([explicitKey, explicitValue]);
   242→      continue;
   243→    }
   244→
   245→    const singleEntry = Object.entries(mapped);
   246→    if (singleEntry.length === 1) {
   247→      entries.push(singleEntry[0] as [string, unknown]);
   248→    }
   249→  }
   250→
   251→  return entries;
   252→}
   253→
   254→function normalizeHeaderMap(
   255→  input: unknown
   256→): Record<string, string> | undefined {
   257→  const entries = extractHeaderEntries(input);
   258→  if (entries.length === 0) return undefined;
   259→
   260→  const out: Record<string, string> = {};
   261→  for (const [key, value] of entries) {
   262→    const normalizedValue = normalizeHeaderValue(value);
   263→    if (!normalizedValue) continue;
   264→    const trimmedKey = key.trim();
   265→    const trimmedValue = normalizedValue.trim();
   266→    if (!trimmedKey || !trimmedValue) continue;
   267→    out[trimmedKey] = trimmedValue;
   268→  }
   269→  return Object.keys(out).length > 0 ? out : undefined;
   270→}
   271→
   272→function nonEmptyTrimmedString(value: unknown): string | null {
   273→  if (typeof value !== "string") return null;
   274→  const trimmed = value.trim();
   275→  return trimmed.length > 0 ? trimmed : null;
   276→}
   277→
   278→function headerMapHasKeyIgnoreCase(
   279→  headers: Record<string, string>,
   280→  targetKey: string
   281→): boolean {
   282→  const normalizedTarget = targetKey.trim().toLowerCase();
   283→  return Object.keys(headers).some(
   284→    (key) => key.trim().toLowerCase() === normalizedTarget
   285→  );
   286→}
   287→
   288→function headerMapGetIgnoreCase(
   289→  headers: Record<string, string>,
   290→  targetKey: string
   291→): string | null {
   292→  const normalizedTarget = targetKey.trim().toLowerCase();
   293→  const key = Object.keys(headers).find(
   294→    (candidate) => candidate.trim().toLowerCase() === normalizedTarget
   295→  );
   296→  if (!key) return null;
   297→  const value = headers[key];
   298→  return typeof value === "string" ? value : null;
   299→}"}]},"parent_tool_use_id":"toolu_0137tJMrTYEPKnzNPp3KBrWT","session_id":"48f40736-6e47-4899-b6f0-08ddcdec91c0","uuid":"48a7b991-d67a-4e73-a46e-06c8517edc62"}

