{"type":"user","message":{"role":"user","content":[{"tool_use_id":"toolu_01VkLfr6iko9EKSpAzncd5y1","type":"tool_result","content":"     1→import type { Request, RequestHandler } from "express";
     2→import type { IncomingHttpHeaders } from "node:http";
     3→import { betterAuth } from "better-auth";
