   115→  async function ensureMigrations(
   116→    connectionString: string,
   117→    label: string,
   118→    opts?: EnsureMigrationsOptions,
   119→  ): Promise<MigrationSummary> {
   120→    const autoApply = opts?.autoApply === true;
   121→    let state = await inspectMigrations(connectionString);
   122→    if (state.status === "needsMigrations" && state.reason === "pending-migrations") {
   123→      const repair = await reconcilePendingMigrationHistory(connectionString);
   124→      if (repair.repairedMigrations.length > 0) {
   125→        logger.warn(
   126→          { repairedMigrations: repair.repairedMigrations },
   127→          `${label} had drifted migration history; repaired migration journal entries from existing schema state.`,
   128→        );
   129→        state = await inspectMigrations(connectionString);
   130→        if (state.status === "upToDate") return "already applied";
   131→      }
   132→    }
   133→    if (state.status === "upToDate") return "already applied";
   134→    if (state.status === "needsMigrations" && state.reason === "no-migration-journal-non-empty-db") {
   135→      logger.warn(
   136→        { tableCount: state.tableCount },
   137→        `${label} has existing tables but no migration journal. Run migrations manually to sync schema.`,
   138→      );
   139→      const apply = autoApply ? true : await promptApplyMigrations(state.pendingMigrations);
   140→      if (!apply) {
   141→        logger.warn(
   142→          { pendingMigrations: state.pendingMigrations },
   143→          `${label} has pending migrations; continuing without applying. Run pnpm db:migrate to apply before startup.`,
   144→        );
   145→        return "pending migrations skipped";
   146→      }
   147→  
   148→      logger.info({ pendingMigrations: state.pendingMigrations }, `Applying ${state.pendingMigrations.length} pending migrations for ${label}`);
   149→      await applyPendingMigrations(connectionString);
   150→      return "applied (pending migrations)";
   151→    }
   152→  
   153→    const apply = autoApply ? true : await promptApplyMigrations(state.pendingMigrations);
   154→    if (!apply) {
   155→      logger.warn(
   156→        { pendingMigrations: state.pendingMigrations },
   157→        `${label} has pending migrations; continuing without applying. Run pnpm db:migrate to apply before startup.`,
   158→      );
   159→      return "pending migrations skipped";
   160→    }
   161→  
   162→    logger.info({ pendingMigrations: state.pendingMigrations }, `Applying ${state.pendingMigrations.length} pending migrations for ${label}`);
   163→    await applyPendingMigrations(connectionString);
   164→    return "applied (pending migrations)";
   165→  }
