{"type":"user","message":{"role":"user","content":[{"tool_use_id":"toolu_015nM14eDBwdMJaYoWh6djYe","type":"tool_result","content":"     1→import { createHash, randomUUID } from "node:crypto";
     2→import path from "node:path";
     3→import type { StorageService, StorageProvider, PutFileInput, PutFileResult } from "./types.js";
     4→import { badRequest, forbidden, unprocessable } from "../errors.js";
     5→
     6→const MAX_SEGMENT_LENGTH = 120;
     7→
     8→function sanitizeSegment(value: string): string {
     9→  const cleaned = value
    10→    .trim()
    11→    .replace(/[^a-zA-Z0-9._-]+/g, "_")
    12→    .replace(/_{2,}/g, "_")
    13→    .replace(/^_+|_+$/g, "");
    14→  if (!cleaned) return "file";
    15→  return cleaned.slice(0, MAX_SEGMENT_LENGTH);
    16→}
    17→
    18→function normalizeNamespace(namespace: string): string {
    19→  const normalized = namespace
    20→    .split("/")
    21→    .map((entry) => entry.trim())
    22→    .filter((entry) => entry.length > 0)
    23→    .map((entry) => sanitizeSegment(entry));
    24→  if (normalized.length === 0) return "misc";
    25→  return normalized.join("/");
    26→}
    27→
    28→function splitFilename(filename: string | null): { stem: string; ext: string } {
    29→  if (!filename) return { stem: "file", ext: "" };
    30→  const base = path.basename(filename).trim();
    31→  if (!base) return { stem: "file", ext: "" };
    32→
    33→  const extRaw = path.extname(base);
    34→  const stemRaw = extRaw ? base.slice(0, base.length - extRaw.length) : base;
    35→  const stem = sanitizeSegment(stemRaw);
    36→  const ext = extRaw
    37→    .toLowerCase()
    38→    .replace(/[^a-z0-9.]/g, "")
    39→    .slice(0, 16);
    40→  return {
    41→    stem,
    42→    ext,
    43→  };
    44→}
    45→
    46→function ensureCompanyPrefix(companyId: string, objectKey: string): void {
    47→  const expectedPrefix = `${companyId}/`;
    48→  if (!objectKey.startsWith(expectedPrefix)) {
    49→    throw forbidden("Object does not belong to company");
    50→  }
    51→  if (objectKey.includes("..")) {
    52→    throw badRequest("Invalid object key");
    53→  }
    54→}
    55→
    56→function hashBuffer(input: Buffer): string {
    57→  return createHash("sha256").update(input).digest("hex");
    58→}
    59→
    60→function buildObjectKey(companyId: string, namespace: string, originalFilename: string | null): string {
    61→  const ns = normalizeNamespace(namespace);
    62→  const now = new Date();
    63→  const year = String(now.getUTCFullYear());
    64→  const month = String(now.getUTCMonth() + 1).padStart(2, "0");
    65→  const day = String(now.getUTCDate()).padStart(2, "0");
    66→  const { stem, ext } = splitFilename(originalFilename);
    67→  const suffix = randomUUID();
    68→  const filename = `${suffix}-${stem}${ext}`;
    69→  return `${companyId}/${ns}/${year}/${month}/${day}/${filename}`;
    70→}
    71→
    72→function assertPutFileInput(input: PutFileInput): void {
    73→  if (!input.companyId || input.companyId.trim().length === 0) {
    74→    throw unprocessable("companyId is required");
    75→  }
    76→  if (!input.namespace || input.namespace.trim().length === 0) {
    77→    throw unprocessable("namespace is required");
    78→  }
    79→  if (!input.contentType || input.contentType.trim().length === 0) {
    80→    throw unprocessable("contentType is required");"}]},"parent_tool_use_id":"toolu_01TTwjNuFdHcaSS3wGNGzUJr","session_id":"48f40736-6e47-4899-b6f0-08ddcdec91c0","uuid":"baf738ce-cb78-4ac6-bc30-9d5907c122a0"}

