{"type":"user","message":{"role":"user","content":[{"tool_use_id":"toolu_01WRAqW1myC89CjBEuRFkbyy","type":"tool_result","content":"     1→import type { AdapterExecutionContext, AdapterExecutionResult } from "../types.js";
     2→import { asString, asNumber, parseObject } from "../utils.js";
     3→
     4→export async function execute(ctx: AdapterExecutionContext): Promise<AdapterExecutionResult> {
     5→  const { config, runId, agent, context } = ctx;
     6→  const url = asString(config.url, "");
     7→  if (!url) throw new Error("HTTP adapter missing url");
     8→
     9→  const method = asString(config.method, "POST");
    10→  const timeoutMs = asNumber(config.timeoutMs, 0);
    11→  const headers = parseObject(config.headers) as Record<string, string>;
    12→  const payloadTemplate = parseObject(config.payloadTemplate);
    13→  const body = { ...payloadTemplate, agentId: agent.id, runId, context };
    14→
    15→  const controller = new AbortController();
    16→  const timer = timeoutMs > 0 ? setTimeout(() => controller.abort(), timeoutMs) : null;
    17→
    18→  try {
    19→    const res = await fetch(url, {
    20→      method,
    21→      headers: {
    22→        "content-type": "application/json",
    23→        ...headers,
    24→      },
    25→      body: JSON.stringify(body),
    26→      ...(timer ? { signal: controller.signal } : {}),
    27→    });
    28→
    29→    if (!res.ok) {
    30→      throw new Error(`HTTP invoke failed with status ${res.status}`);
    31→    }
    32→
    33→    return {
    34→      exitCode: 0,
    35→      signal: null,
    36→      timedOut: false,
    37→      summary: `HTTP ${method} ${url}`,
    38→    };
    39→  } finally {
    40→    if (timer) clearTimeout(timer);
    41→  }
    42→}
    43→"}]},"parent_tool_use_id":"toolu_01BNpawgB1VtJoJ5JZG87tDt","session_id":"48f40736-6e47-4899-b6f0-08ddcdec91c0","uuid":"9cb2ae67-c086-4280-be48-d14be8d1566d"}

