{"type":"user","message":{"role":"user","content":[{"tool_use_id":"toolu_01LuvHNpE1afmW1NeqsP1UYJ","type":"tool_result","content":"   897→  async function reapOrphanedRuns(opts?: { staleThresholdMs?: number }) {
   898→    const staleThresholdMs = opts?.staleThresholdMs ?? 0;
   899→    const now = new Date();
   900→
   901→    // Find all runs in "queued" or "running" state
   902→    const activeRuns = await db
   903→      .select()
   904→      .from(heartbeatRuns)
   905→      .where(inArray(heartbeatRuns.status, ["queued", "running"]));
   906→
   907→    const reaped: string[] = [];
   908→
   909→    for (const run of activeRuns) {
   910→      if (runningProcesses.has(run.id)) continue;
   911→
   912→      // Apply staleness threshold to avoid false positives
   913→      if (staleThresholdMs > 0) {
   914→        const refTime = run.updatedAt ? new Date(run.updatedAt).getTime() : 0;
   915→        if (now.getTime() - refTime < staleThresholdMs) continue;
   916→      }
   917→
   918→      await setRunStatus(run.id, "failed", {
   919→        error: "Process lost -- server may have restarted",
   920→        errorCode: "process_lost",
   921→        finishedAt: now,
   922→      });
   923→      await setWakeupStatus(run.wakeupRequestId, "failed", {
   924→        finishedAt: now,
   925→        error: "Process lost -- server may have restarted",
   926→      });
   927→      const updatedRun = await getRun(run.id);
   928→      if (updatedRun) {
   929→        await appendRunEvent(updatedRun, 1, {
   930→          eventType: "lifecycle",
   931→          stream: "system",
   932→          level: "error",
   933→          message: "Process lost -- server may have restarted",
   934→        });
   935→        await releaseIssueExecutionAndPromote(updatedRun);
   936→      }
   937→      await finalizeAgentStatus(run.agentId, "failed");
   938→      await startNextQueuedRunForAgent(run.agentId);
   939→      runningProcesses.delete(run.id);
   940→      reaped.push(run.id);
   941→    }
   942→
   943→    if (reaped.length > 0) {
   944→      logger.warn({ reapedCount: reaped.length, runIds: reaped }, "reaped orphaned heartbeat runs");
   945→    }
   946→    return { reaped: reaped.length, runIds: reaped };
   947→  }
