  1003→  async function startNextQueuedRunForAgent(agentId: string) {
  1004→    return withAgentStartLock(agentId, async () => {
  1005→      const agent = await getAgent(agentId);
  1006→      if (!agent) return [];
  1007→      const policy = parseHeartbeatPolicy(agent);
  1008→      const runningCount = await countRunningRunsForAgent(agentId);
  1009→      const availableSlots = Math.max(0, policy.maxConcurrentRuns - runningCount);
  1010→      if (availableSlots <= 0) return [];
  1011→
  1012→      const queuedRuns = await db
  1013→        .select()
  1014→        .from(heartbeatRuns)
  1015→        .where(and(eq(heartbeatRuns.agentId, agentId), eq(heartbeatRuns.status, "queued")))
  1016→        .orderBy(asc(heartbeatRuns.createdAt))
  1017→        .limit(availableSlots);
  1018→      if (queuedRuns.length === 0) return [];
  1019→
  1020→      const claimedRuns: Array<typeof heartbeatRuns.$inferSelect> = [];
  1021→      for (const queuedRun of queuedRuns) {
  1022→        const claimed = await claimQueuedRun(queuedRun);
  1023→        if (claimed) claimedRuns.push(claimed);
  1024→      }
  1025→      if (claimedRuns.length === 0) return [];
  1026→
  1027→      for (const claimedRun of claimedRuns) {
  1028→        void executeRun(claimedRun.id).catch((err) => {
  1029→          logger.error({ err, runId: claimedRun.id }, "queued heartbeat execution failed");
  1030→        });
  1031→      }
  1032→      return claimedRuns;
  1033→    });
  1034→  }
