  1036→  async function executeRun(runId: string) {
  1037→    let run = await getRun(runId);
  1038→    if (!run) return;
  1039→    if (run.status !== "queued" && run.status !== "running") return;
  1040→
  1041→    if (run.status === "queued") {
  1042→      const claimed = await claimQueuedRun(run);
  1043→      if (!claimed) {
  1044→        // Another worker has already claimed or finalized this run.
  1045→        return;
  1046→      }"}]},"parent_tool_use_id":"toolu_01BNpawgB1VtJoJ5JZG87tDt","session_id":"48f40736-6e47-4899-b6f0-08ddcdec91c0","uuid":"7ecc5008-64e8-4d76-bbd7-f9b4fb379bc2"}

